generation_timestamp": "2025-12-12T03:54:50.376995", "active_competencies_per_level": {"1": 0, "2": 11, "4": 4, "6": 0}}}, "train_the_trainer": {"1": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 88.9, "objective_text": "The participant is able to bring systems thinking into PMT and inspire others to do the same. The participant can independently define or question the system limits and scope within the context of PMT's operational framework.", "competency_name": "Systems Thinking"}, "4": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 77.8, "objective_text": "The participant is able to evaluate concepts with regard to all life cycle phases, identify weaknesses in the methodology, and make suggestions for improvement within the context of PMT's existing frameworks and practices.", "competency_name": "Lifecycle Consideration"}, "5": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 88.9, "objective_text": "The participant is able to bring customer-centric thinking into PMT and inspire others to do the same. The participant can independently define value-driven methods for projects using the company's existing frameworks and approaches.", "competency_name": "Customer / Value Orientation"}, "6": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 77.8, "objective_text": "Participants can set guidelines for models and write guidelines for good modeling using PMT's existing tools and methods.", "competency_name": "Systems Modelling and Analysis"}, "7": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 77.8, "objective_text": "Participants are able to manage their relationships with colleagues and superiors in a sustainable manner. They can resolve conflicts, bring different perspectives together, and negotiate sustainable compromises.", "competency_name": "Communication"}, "8": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 100.0, "objective_text": "Participants are able to strategically develop team members so that they continue to develop when finding solutions.", "competency_name": "Leadership"}, "9": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 88.9, "objective_text": "Participants are able to work on complex projects, processes, and tasks in a fully self-organized manner and can guide others in self-organization practices, utilizing the company's existing frameworks for collaboration and communication.", "competency_name": "Self-Organization"}, "10": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 77.8, "objective_text": "The participant is able to identify shortcomings in the project management process and make suggestions for improvement. They can successfully communicate reports, plans, and orders to all stakeholders and utilize the basic project management tools available within the company.", "competency_name": "Project Management"}, "11": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 77.8, "objective_text": "Participants can evaluate decisions and establish overarching decision-making processes. They can introduce decision methods company-wide and set up the decision management toolchain, tailored to the specific needs of PMT's evolving organizational structure.", "competency_name": "Decision Management"}, "12": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 77.8, "objective_text": "The participant can define a comprehensive information management process tailored to PMT's needs, establish documentation methods and standa