zed": true, "level_name": "Mastering SE", "gap_percentage": 85.7, "objective_text": "The participant is able to evaluate concepts with regard to all life cycle phases, identify weaknesses in the methodology, and make suggestions for improvement, considering the absence of established processes, methods, and tools within PMT.", "competency_name": "Lifecycle Consideration"}, "5": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 85.7, "objective_text": "The participant is able to bring customer-centric thinking into PMT and inspire others to do the same. The participant can independently define value-driven methods for projects within the context of PMT's unique operational framework.", "competency_name": "Customer / Value Orientation"}, "6": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 92.9, "objective_text": "Participants can set guidelines for models and write guidelines for good modeling using the company's existing tools and methods.", "competency_name": "Systems Modelling and Analysis"}, "7": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 93.3, "objective_text": "Participants are able to manage their relationships with colleagues and superiors in a sustainable manner. They can resolve conflicts, bring different perspectives together, and negotiate sustainable compromises.", "competency_name": "Communication"}, "8": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 100.0, "objective_text": "Participants are able to strategically develop team members so that they continue to develop when finding solutions.", "competency_name": "Leadership"}, "9": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 92.9, "objective_text": "Participants are able to work on complex projects, processes, and tasks in a fully self-organized manner and can guide others in self-organization practices, utilizing the company's existing frameworks and collaborative tools to enhance team autonomy and effectiveness.", "competency_name": "Self-Organization"}, "10": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 100.0, "objective_text": "The participant is able to identify shortcomings in the project management process and make suggestions for improvement. They can successfully communicate reports, plans, and orders to all stakeholders and use advanced tool functions effectively, even in the absence of established processes, methods, or tools within PMT.", "competency_name": "Project Management"}, "11": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 100.0, "objective_text": "Participants can evaluate decisions and establish overarching decision-making processes. They can introduce decision methods company-wide and set up the decision management toolchain, tailored to the unique needs of PMT's current lack of established processes, methods, and tools.", "competency_name": "Decision Management"}, "12": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 86.7, "objective_text": "The participant can define a comprehensive information management process, establish documentation methods and standards, and set up the information management toolchain for PMT, utilizing any existing tools and methods as they are developed.", "competency_name": "Information Management"}, "13": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 93.3, "objective_text": "The participant is able to recognize all relevant configuration items and build a complete configuration across all items. They can identify improvements, propose solutions, support others, and set up the relevant tool landscape, utilizing the existing tools and methods available within PMT.", "competency_name": "Configuration Management"}, "14": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 92.3, "objective_text": "Participants are able to recognize shortcomings in the requirements definition process and develop suggestions for improvement. They can guide colleagues in requirements formulation and introduce tailored requirements tools that align with PMT's operational needs.", "competency_name": "Requirements Definition"}, "15": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 92.3, "objective_text": "Participants can recognize shortcomings in the system architecting process and develop suggestions for improvement. They can create and manage high-complexity models using the existing tools and methods available within PMT and set up a tailored toolchain for system modeling.", "competency_name": "System Architecting"}, "16": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 92.3, "objective_text": "The participant is able to set up a test strategy and test plans at an early stage, conduct design reviews, and establish verification and validation processes using the company's existing frameworks. They can optimize the test tool landscape for the organization, even in the absence of defined processes, methods, and tools.", "competency_name": "Integration, Verification, Validation"}, "17": {"level": 6, "source": "pmt_customized", "customized": true, "level_name": "Mastering SE", "gap_percentage": 100.0, "objective_text": "Participants are able to define the organizational processes for operations, service, and maintenance specific to PMT's operational framework and place them in the context of the entire life cycle.", "competency_name": "Operation and Support"}, "18": {"level