188	39	28	phase2_employee	unknown_roles	{"username": "phase2_task_28_1763178630773_ferfz", "competencies": [{"description": "The ability to apply fundamental concepts of systems thinking in Systems Engineering and understand the role of one's own system in its overall context.", "competencyId": 1, "requiredLevel": 4, "competencyArea": "Core", "competencyName": "Systems Thinking"}, {"description": "The ability to consider all lifecycle phases (except the operational phase) in system requirements, architectures, and designs during system development.", "competencyId": 4, "requiredLevel": 2, "competencyArea": "Core", "competencyName": "Lifecycle Consideration"}, {"description": "The ability to place agile values and customer benefits at the center of development.", "competencyId": 5, "requiredLevel": 4, "competencyArea": "Core", "competencyName": "Customer / Value Orientation"}, {"description": "The ability to provide precise data and information using cross-domain models to support technical understanding and decision-making.", "competencyId": 6, "requiredLevel": 2, "competencyArea": "Core", "competencyName": "Systems Modelling and Analysis"}, {"description": "The ability to communicate constructively, efficiently, and consciously across domains, while capturing and considering the feelings of others and maintaining sustainable and fair relationships with colleagues and supervisors.", "competencyId": 7, "requiredLevel": 4, "competencyArea": "Social / Personal", "competencyName": "Communication"}, {"description": "The ability to select appropriate goals for a system or system element, negotiate when necessary, and efficiently achieve them with a team while guiding team members in problem-solving when needed.", "competencyId": 8, "requiredLevel": 4, "competencyArea": "Social / Personal", "competencyName": "Leadership"}, {"description": "The ability to organize oneself and manage tasks independently.", "competencyId": 9, "requiredLevel": 4, "competencyArea": "Social / Personal", "competencyName": "Self-Organization"}, {"description": "The ability to identify, plan, coordinate, and adapt activities to deliver a satisfactory system, product, or service with appropriate quality, budget, and timeline.", "competencyId": 10, "requiredLevel": 4, "competencyArea": "Management", "competencyName": "Project Management"}, {"description": "The ability to identify, characterize, and evaluate an objective set of alternatives in a structured and analytical manner while considering risks and opportunities.", "competencyId": 11, "requiredLevel": 2, "competencyArea": "Management", "competencyName": "Decision Management"}, {"description": "The ability to address all aspects of information for specific stakeholders to deliver the right information at the right time with appropriate security.", "competencyId": 12, "requiredLevel": 2, "competencyArea": "Management", "competencyName": "Information Management"}, {"description": "The ability to consistently design system functions, performance, and physical properties across the lifecycle and ensure consistency.", "competencyId": 13, "requiredLevel": 1, "competencyArea": "Management", "competencyName": "Configuration Management"}, {"description": "The ability to analyze stakeholder needs and expectations and derive system requirements from them.", "competencyId": 14, "requiredLevel": 2, "competencyArea": "Technical", "competencyName": "Requirements Definition"}, {"description": "The ability to define system-related elements, their hierarchy, interfaces, behavior, and associated derived requirements to develop an implementable solution.", "competencyId": 15, "requiredLevel": 2, "competencyArea": "Technical", "competencyName": "System Architecting"}, {"description": "The ability to integrate a set of system elements into a verifiable or validatable unit, and provide objective evidence that a system meets specified requirements (verification) or achieves its intended properties in the intended operational environment (validation).", "competencyId": 16, "requiredLevel": 2, "competencyArea": "Technical", "competencyName": "Integration, Verification, Validation"}, {"description": "The ability to commission, operate, and maintain a system's capabilities and functionalities throughout its lifetime.", "competencyId": 17, "requiredLevel": 2, "competencyArea": "Technical", "competencyName": "Operation and Support"}, {"description": "The ability to apply methods that support agile values in the project context and enable parallel work.", "competencyId": 18, "requiredLevel": 4, "competencyArea": "Technical", "competencyName": "Agile Methods"}]}	null	2025-11-15 03:51:58.819138	2025-11-15 03:52:37.200324
