--

CREATE TABLE public.learning_format (
    id integer NOT NULL,
    format_key character varying(50) NOT NULL,
    format_name character varying(255) NOT NULL,
    short_name character varying(50) NOT NULL,
    description text,
    icon character varying(10),
    mode_of_delivery character varying(20),
    communication_type character varying(20),
    collaboration_type character varying(20),
    learning_type character varying(20),
    participant_min integer DEFAULT 1,
    participant_max integer,
    max_level_achievable integer,
    is_e_learning boolean DEFAULT false,
    is_passive boolean DEFAULT false,
    is_recommended boolean DEFAULT false,
    effort_content_creation integer,
    effort_content_update integer,
    effort_per_training integer,
    advantages text,
    disadvantages text,
    display_order integer DEFAULT 0,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT learning_format_collaboration_type_check CHECK (((collaboration_type)::text = ANY ((ARRAY['group'::character varying, 'individual'::character varying])::text[]))),
    CONSTRAINT learning_format_communication_type_check CHECK (((communication_type)::text = ANY ((ARRAY['synchronous'::character varying, 'asynchronous'::character varying, 'hybrid'::character varying])::text[]))),
    CONSTRAINT learning_format_effort_content_creation_check CHECK (((effort_content_creation >= 1) AND (effort_content_creation <= 5))),
